export function AdminDashboard() {
  const [stats, setStats] = useState({ users: 0, active: 0, blocked: 0 });

  useEffect(() => {
    load();
  }, []);

  const load = async () => {
    const data = await getUsers();
    const users = data.content || [];

    setStats({
      users: users.length,
      active: users.filter((u) => u.status === "Активен").length,
      blocked: users.filter((u) => u.status === "Заблокирован").length,
    });
  };

  return (
    <DashboardLayout>
      <div className="p-6 grid grid-cols-3 gap-6">
        <Card title="Всего пользователей" value={stats.users} />
        <Card title="Активные" value={stats.active} />
        <Card title="Заблокированные" value={stats.blocked} />
      </div>
    </DashboardLayout>
  );
}

function Card({ title, value }) {
  return (
    <div className="p-6 rounded-2xl bg-gradient-to-br from-indigo-500 to-purple-600 text-white shadow-xl">
      <h3 className="text-lg">{title}</h3>
      <p className="text-3xl font-bold mt-2">{value}</p>
    </div>
  );
}
